insert into weekly_calendar (sort_order, day, training, session, intensity_rule, notes) values (1, 'Tuesday', 'S&C', 'Day C — judo-specific conditioning', 'Medicine-ball throws, entries, grip, carries', 'Transfer-focused, not a beatdown.');
insert into weekly_calendar (sort_order, day, training, session, intensity_rule, notes) values (2, 'Wednesday', 'Judo', 'Technical / randori', 'Sport priority', 'Protect practice quality.');
insert into weekly_calendar (sort_order, day, training, session, intensity_rule, notes) values (3, 'Thursday', 'S&C', 'Day B — full-body strength', 'Productive but non-grinding', 'Trim grip first if Friday judo will be hard.');
insert into weekly_calendar (sort_order, day, training, session, intensity_rule, notes) values (4, 'Friday', 'Judo', 'Technical / randori', 'Sport priority', 'Avoid arriving finger-fried.');
insert into weekly_calendar (sort_order, day, training, session, intensity_rule, notes) values (5, 'Saturday', 'Recovery', 'Walk / mobility / easy zone 2 optional', 'Low stress', 'No hard leg work.');
insert into weekly_calendar (sort_order, day, training, session, intensity_rule, notes) values (6, 'Sunday', 'Judo', 'Technical / randori', 'Sport priority', 'Review fatigue before Monday.');
insert into global_rules (priority, rule, implementation) values (1, 'Protect judo quality first', 'If Wednesday/Friday randori quality drops: trim Thursday grip, then Thursday accessories, then Day C density, then main lifts.');
insert into global_rules (priority, rule, implementation) values (2, 'Use RPE autoregulation', 'Add load only when sets are at/below target RPE with clean technique and good speed.');
insert into global_rules (priority, rule, implementation) values (3, 'Deload every 4th week', 'Reduce hard sets by 35–50%, lower intensity by 5–10%, avoid failure.');
insert into global_rules (priority, rule, implementation) values (4, 'Grip is frequent but tightly dosed', 'Goal is grip resilience, not arriving at judo with dead fingers and elbows.');
insert into global_rules (priority, rule, implementation) values (5, 'Power work must stay fast', 'Medicine-ball throws and speed lifts stop when reps slow or mechanics degrade.');
insert into global_rules (priority, rule, implementation) values (6, 'Accessories are optional under fatigue', 'Cut hypertrophy accessories first after hard randori or poor sleep.');
